#!/usr/bin/env node

import { writeFile } from "node:fs/promises";
import path from "node:path";
import process from "node:process";

import { parseApiCalls } from "./api-call-utils.mjs";

const outputPath = path.resolve(process.cwd(), "src/generated/api-calls.gen.ts");
const entries = await parseApiCalls();

const header = [
  "// This file is auto-generated by scripts/generate-api-calls.mjs",
  "",
  "export interface RaastApiCall {",
  '  readonly method: "GET" | "POST" | "PUT" | "DELETE";',
  "  readonly name: string;",
  "  readonly summary: string;",
  "  readonly url: string;",
  "}",
  "",
  "export const apiCalls: ReadonlyArray<RaastApiCall> = [",
];

const body = entries.map(
  (entry) =>
    `  { method: ${JSON.stringify(entry.method)}, url: ${JSON.stringify(entry.url)}, name: ${JSON.stringify(entry.name)}, summary: ${JSON.stringify(entry.summary)} },`,
);

const footer = ["];", ""];

await writeFile(outputPath, [...header, ...body, ...footer].join("\n"), "utf8");

console.log(
  `Generated ${path.relative(process.cwd(), outputPath)} with ${entries.length} API calls`,
);
